#include <stdio.h>

int main() {
    int n, k, d;
    scanf("%d %d %d", &n, &k, &d);
    k = n < k ? n : k;
    int cnt[n+1];
    int cn[n+1];
    for (int i = 0; i <= n; i++) {
        cnt[i] = 0;
        cn[i] = 0;
    }
    cnt[0] = cn[0] = 1;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= k; j++) {
            if (i >= j) {
                cnt[i] += cnt[i-j];
            }
            if (i >= j && j < d) {
                cn[i] += cn[i-j];
            }
        }
    }
    int s1 = cnt[n];
    int s2 = cn[n];
    printf("%d\n", (s1 - s2) % 1000000007);
    return 0;
}
